@ARTICLE{10.1016/j.carrev.2022.03.013,
	author = {Bastos MB and McConkey H and Malkin O, den Uil C and Daemen J and Patterson T and Wolff Q and Kardys I and Schreuder J and Lenzen M and Zijlstra F and Redwood S and Van Mieghem NM},
	title = {Effect of Next Generation Pulsatile Mechanical Circulatory Support on Cardiac Mechanics: The PULSE Trial.},
	journal = {Cardiovasc Revasc Med},
	year = {2022},
	abstract = {OBJECTIVES: To describe hemodynamic effects of iVAC2L mechanical circulatory support (MCS). BACKGROUND: MCS is increasingly used in the context of high-risk percutaneous coronary intervention (PCI). The effect of the pulsatile iVAC2L MCS on left ventricular loading conditions and myocardial oxygen consumption (MVO2) is unknown. METHODS: This prospective single-arm two-center study included 29 patients who underwent high-risk PCI with iVAC2L MCS using simultaneous invasive pulmonary pressure monitoring and left ventricular pressure-volume analysis. Hemodynamic recordings were performed during steady state conditions with MCS off and on before and after PCI. Pressure-volume variations were analyzed to denote responders and non-responders. RESULTS: The mean age was 74 (IQR: 70-81) years and the mean SYNTAX score was 31 ± 8.3. Left ventricular unloading with iVAC2L MCS was demonstrated in 22 out of 27 patients with complete PV studies. Patients with moderate or severe mitral regurgitation or presenting with acute coronary syndrome (ACS) had higher filling pressures and volumes and were most responsive to iVAC2L unloading (9/10 patients with moderate or severe MR and 11/11 patients with ACS). Pulsatile MCS activation reduced MAP (-4%), SBP (-9%), ESP (-11%), ESV (-15%) and EDV (-4%) among responders but not among non-responders. Responders experienced significant reductions in afterload (Ea: -19%) with increases in stroke volume (+11%) and cardiac output (+11%). CONCLUSIONS: Pulsatile iVAC2L MCS in patients with advanced coronary artery disease at high to prohibitive operative risk resulted in LV unloading and reduced myocardial oxygen consumption particularly in patients with ACS or significant MR with higher filling pressures at baseline. CLINICAL TRIAL REGISTRATION: NCT03200990.},
	doi = {10.1016/j.carrev.2022.03.013},
	pmid = {35331637 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/aor.14207,
	author = {Yu XY and Shi JW and Zang YR and Zhang JM and Liu ZG},
	title = {Factors influencing the functional status of aortic valve in ovine models supported by continuous-flow left ventricular assist device.},
	journal = {Artif Organs},
	year = {2022},
	abstract = {OBJECTIVES: An acute animal experiment was performed to observe factors influencing the functional status of the aortic valve functional status after continuous-flow left ventricular assist device (CF-LVAD) implantation in an ovine model, and a physiologic predictive model was established. METHODS: A CF-LVAD model was established in Small Tail Han sheep. The initial heart rate (HR) was set to 60 beats/min, and grouping was performed at an interval of 20 beats/min. In all groups, the pump speed was started from 2000 rpm and was gradually increased by 50-100 rpm. A multi-channel physiological recorder recorded the HR, aortic pressure, central venous pressure, and left ventricular systolic pressure (LVSP). A double-channel ultrasonic flowmeter was used to obtain real-time artificial vascular blood flow (ABF). A color Doppler ultrasound device was applied to assess the aortic valve functional status. Multivariate dichotomous logistic regression was used to screen significant variables for predicting the functional status of the aortic valve. RESULTS: Observational studies showed that ABF and the risk of aortic valve closure (AVC) were positively correlated with pump speed at the same HR. Meanwhile, the mean arterial pressure (MAP) was unaltered or slightly increased with increased pump speed. When the pump speed was constant, an increase in HR was associated with a decrease in the size of the aortic valve opening. This phenomenon was accompanied by an initial transient increase in the ABF and MAP, which subsequently decreased. Statistical analysis showed that the AVC was associated with increased pump speed (OR = 1.02, 95% CI = 1.01-1.04, p = 0.001), decreased LVSP (OR = 0.95, 95% CI = 0.91-0.98, p = 0.003), and decreased pulse pressure (OR = 0.82, 95% CI = 0.68-0.96, p = 0.026). ABF or MAP was negatively associated with the risk of AVC (OR < 1). The prediction model of AVC after CF-LVAD implantation exhibited good differentiation (AUC = 0.973, 95% CI = 0.978-0.995) and calibration performance (Hosmer-Lemeshow χ2 = 9.834, p = 0.277 > 0.05). CONCLUSIONS: The pump speed, LVSP, ABF, MAP, and pulse pressure are significant predictors of the risk of AVC. Predictive models built from these predictors yielded good performance in differentiating aortic valve opening and closure after CF-LVAD implantation.},
	doi = {10.1111/aor.14207},
	pmid = {35167127 [Indexed for MEDLINE]},
	note = {PMC9310577}
}

@ARTICLE{10.1053/j.jvca.2022.01.002,
	author = {Mohamed A and Berry TP and Welge JA and Thomas EL and Zhurav L and Kozinn J and Haines MM},
	title = {Angiotensin II in Patients With Shock on Mechanical Circulatory Support: A Single-Center Retrospective Case Series.},
	journal = {J Cardiothorac Vasc Anesth},
	year = {2022},
	abstract = {OBJECTIVES: To describe angiotensin II (ANGII) use in patients on mechanical circulatory support (MCS). To evaluate the efficacy and safety of ANGII in patients with shock on MCS. DESIGN: Retrospective cohort study. SETTING: A single-center, quaternary care academic medical center. PARTICIPANTS: The study comprised critically ill patients on MCS. INTERVENTIONS: None. MEASUREMENTS AND MAIN RESULTS: Fourteen patients were included in this retrospective analysis. The median age was 54 years (44.8, 68.3) and 78.6% were men. Six patients were receiving venoarterial extracorporeal membrane oxygenation support, 4 patients were receiving venovenous extracorporeal membrane oxygenation support, and 4 patients were on left ventricular assist devices. Five patients (36%) achieved hemodynamic response to ANGII at 3 hours, defined as a mean arterial pressure (MAP) of ≥65 mmHg or a 10-mmHg increase in MAP with a decrease or no change in total vasopressor dose. Overall, the median MAP increased from 61 mmHg (51, 73) at baseline to 66 mmHg (58, 71) at 3 hours, and the median norepinephrine dose decreased from 0.45 μg/kg/min (0.28, 0.6) at baseline to 0.2 μg/kg/min (0.18, 0.32) at 3 hours. The in-hospital mortality rate was 78.6%. Two patients experienced severe adverse drug events and 1 patient had a sentinel thrombotic event. CONCLUSIONS: This study suggested that ANGII may provide a salvage treatment option in patients on MCS with refractory vasodilatory shock. There are several safety considerations with the use of ANGII in these patients. Prospective randomized controlled trials are needed to evaluate the safety and efficacy of ANGII in patients on MCS.},
	doi = {10.1053/j.jvca.2022.01.002},
	pmid = {35144869 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jscai.2021.100002,
	author = {Shah T and Lansky AJ and Grines CL and O'Neill WW and Moses JW and Chieffo A and Kapur NK and Chou J},
	title = {Mechanical Circulatory Support in Myocardial Infarction Complicated by Cardiogenic Shock: Impact of Sex and Timing.},
	journal = {J Soc Cardiovasc Angiogr Interv},
	year = {2022},
	abstract = {BACKGROUND: Sex differences in presentation, treatment, and outcomes persist in patients with acute myocardial infarction complicated by cardiogenic shock (AMICS). Sex-based outcomes of patients with AMICS undergoing percutaneous coronary intervention (PCI) with percutaneous left ventricular assist device (pLVAD) support are poorly defined. METHODS: From January 2017 to August 2019, consecutive patients undergoing PCI who received Impella support within 48 ​hours of myocardial infarction were enrolled in the prospective RECOVER III postmarket registry. In-hospital survival and predictors of mortality were compared by sex. RESULTS: A total of 358 patients (276 men and 82 women) were included. Women had lower baseline mean arterial pressure and shorter duration of pLVAD support compared with men. In-hospital adverse events were similar in women and men, including mortality (54% versus 46%, P = .25), major bleeding (11% versus 10%, P = .83), and vascular complications requiring surgery (8.5% versus 4%, P = .10). Women had better survival with pre-PCI versus post-PCI pLVAD implantation (59% versus 34%, P = .03), whereas survival in men was similar regardless of pre- versus post-PCI pLVAD support (56% versus 50%, P = .39). The number of inotrope/vasopressor use pre-pLVAD was the strongest predictor of mortality in women (OR 3.03, P = .01) but not in men (OR 1.18, P = .25). CONCLUSIONS: Survival of patients with AMICS treated with PCI and Impella support was 52% at hospital discharge and was similar for women and men. Women with AMICS may derive greater benefit from early pLVAD support prior to escalation of inotrope/vasopressors and had no evidence of increased risk of access-related complications.},
	doi = {10.1016/j.jscai.2021.100002},
	pmid = {39130134},
	note = {PMC11307664}
}

@ARTICLE{10.1016/j.amjcard.2021.12.045,
	author = {Vidula H and Altintas O and McNitt S and DeVore AD and Birati EY and Genuardi MV and Sheikh FH and Polonsky B and Alexis JD and Gosev I and Bisognano JD and Kutyifa V and Seidmann A and Goldenberg I},
	title = {Low Blood Pressure Threshold for Adverse Outcomes During Left Ventricular Assist Device Support.},
	journal = {Am J Cardiol},
	year = {2022},
	abstract = {It has been suggested that maintaining low mean arterial pressure (MAP) in left ventricular assist device (LVAD) recipients is associated with a reduced risk of stroke/death. However, the lower limit of the optimal MAP range has not been established. We aimed to identify this lower limit in a contemporary cohort of LVAD recipients with frequent longitudinal MAP measurements. We analyzed 86,651 MAP measurements in 309 patients with an LVAD (32% LVADs with full magnetic levitation of the impeller) at a tertiary medical center during a mean follow-up of 1.7 ± 1.1 years. Cox proportional hazards regression modeling was used to study the association of serial MAP measurements with stroke/death within 3 years after index discharge. Multivariate analysis identified MAP ≤75 mm Hg, compared with MAP >75 mm Hg, as the low MAP threshold associated with increased risk of death (hazard ratio [HR] 4.74, 95% confidence interval [CI] 2.85 to 7.87, p <0.001), stroke (HR 2.72;, 95% CI 1.39 to 5.33, p = 0.01), and stroke/death (HR 4.45, 95% CI 2.83 to 6.99, p <0.001). The risk associated with MAP ≤75 mm Hg was consistent in subgroups categorized by age, gender, race, device type, renal function, right-sided heart failure, and blood pressure medications. In conclusion, our findings suggest that maintaining MAP ≤75 mm Hg during long-term follow-up in LVAD recipients is associated with increased risk of stroke/death regardless of risk factors or medical management.},
	doi = {10.1016/j.amjcard.2021.12.045},
	pmid = {35063265 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cardfail.2021.11.001,
	author = {Belkin MN and Alenghat FJ and Besser SA and Pinney SP and Grinstein J},
	title = {Improved Prognostic Performance of Cardiac Power Output With Right Atrial Pressure: A Subanalysis of the ESCAPE Trial.},
	journal = {J Card Fail},
	year = {2022},
	abstract = {BACKGROUND: The initial derivation of cardiac power output (CPO) included the difference between mean arterial pressure (MAP) and right atrial pressure (RAP) in the numerator, before multiplying by cardiac output (CO). We hypothesized that the inclusion of RAP (CPO-RAP) would enhance the prognostic performance of this parameter in those with an elevated RAP. METHODS AND RESULTS: We obtained patient-level data from the ESCAPE trial via the Biolincc database. Participants with full final hemodynamics were included in the analysis. The CPO-RAP was calculated as [(MAP - RAP) × CO)]/451 Watts (W), and the CPO was calculated as (MAP × CO)/451. The primary outcome was freedom from left ventricular assist device, heart transplant, or death at 6 months. Included participants (n = 157) were a median of 58 years of age (interquartile range [IQR] 49-67 years), 27% were women, and 59% had ischemic cardiomyopathy. The median CPO was 0.70 W (IQR 0.50-0.90 W), and the median CPO-RAP was 0.62 W (IQR 0.47-0.79 W). In univariable logistic regressions, the CPO was not associated with the primary outcome (odds ratio 0.32, 95% confidence interval 0.08-1.29, P = .11), but the CPO-RAP was (odds ratio 0.10, 95% confidence interval 0.02-0.54, P < .01). In Kaplan-Meier analyses, there were no significant difference in outcomes with CPO (76% vs 64%, P = .08), but for CPO-RAP, there were significant differences in outcomes (81% vs 63%, P = .01). When further delineating CPO-RAP by RAP above or below the median, there was no significant difference in the outcome for participants with a RAP 8 or less (94% vs 79%, P = .07), but a significant difference in participants with a RAP of more than 8 mm Hg (66% vs 45%, P < .05). CONCLUSIONS: The inclusion of RAP resulted in a significant association with the primary outcome; CPO alone was not.},
	doi = {10.1016/j.cardfail.2021.11.001},
	pmid = {34774746 [Indexed for MEDLINE]},
	note = {PMC9085968}
}

@ARTICLE{10.1097/MAT.0000000000001606,
	author = {Chivukula VK and Loera G and Dragoljic D and Martinez J and Beckman JA and Li S and Mahr C and Aliseda A},
	title = {A Computational Hemodynamics Approach to Left Ventricular Assist Device (LVAD) Optimization Validated in a Large Patient Cohort.},
	journal = {ASAIO J},
	year = {2022},
	abstract = {With increasing use of left ventricular assist devices (LVAD) it is critical to devise strategies to optimize LVAD speed while controlling mean arterial pressure (MAP) and flow according to patient physiology. The complex interdependency between LVAD speed, MAP, and flow frequently makes optimization difficult under clinical conditions. We propose a method to guide this procedure in silico, narrowing the conditions to test clinically. A computational model of the circulatory network that simulates HF and LVAD support, incorporating LVAD pressure-flow curves was applied retrospectively to anonymized patient hemodynamics data from the University of Washington Medical Center. MAP management on 61 patient-specific computational models with a target of 70 mm Hg, resulting flow for a given LVAD speed was analyzed, and compared to a target output of 5 L/min. Before performing virtual MAP management, 51% had a MAP>70 mm Hg and CO>5 L/min, and 33% had a MAP>70 mm Hg and CO<5 L/min. After changing systemic resistance to meet the MAP target (without adjusting LVAD speed), 84% of cases resulted in CO higher than 5 L/min, with a median CO of 6.79 L/min, using the computational predictive model. Blood pressure management alone is insufficient in meeting both MAP and CO targets, due to the risk of hypervolemia, and requires appropriate LVAD speed optimization to achieve both targets, while preserving right heart health. Such computational tools can narrow down conditions to be tested for each patient, providing significant insight into the pump-patient interplay. LVAD hemodynamic optimization has the potential to reduce complications and improve outcomes.},
	doi = {10.1097/MAT.0000000000001606},
	pmid = {34743140 [Indexed for MEDLINE]}
}

@ARTICLE{10.33549/physiolres.934738,
	author = {Konarik M and Sramko M and Dorazilova Z and Blaha M and Netuka I and Ivak P and Maly J and Szarszoi O},
	title = {Effects of Acute Pump Speed Changes on Cerebral Hemodynamics in Patients With an Implantable Continuous-Flow Left Ventricular Assist Devices.},
	journal = {Physiol Res},
	year = {2021},
	abstract = {Mechanical circulatory support (MCS) with an implantable left ventricular assist device (LVAD) is an established therapeutic option for advanced heart failure. Most of the currently used LVADs generate a continuous stream of blood that decreases arterial pulse pressure. This study investigated whether a change of the pulse pressure during different pump speed settings would affect cerebral autoregulation and thereby affect cerebral blood flow (CBF). The study included 21 haemodynamically stable outpatients with a continuous-flow LVAD (HeartMate II, Abbott, USA) implanted a median of 6 months before the study (interquartile range 3 to 14 months). Arterial blood pressure (measured by finger plethysmography) was recorded simultaneously with CBF (measured by transcranial Doppler ultrasound) during baseline pump speed (8900 rpm [IQR 8800; 9200]) and during minimum and maximum tolerated pump speeds (8000 rpm [IQR 8000; 8200] and 9800 rpm [IQR 9800; 10 000]). An increase in LVAD pump speed by 800 rpm [IQR 800; 1000] from the baseline lead to a significant decrease in arterial pulse pressure and cerebral blood flow pulsatility (relative change ?24% and ?32%, both p < 0.01), but it did not affect mean arterial pressure and mean CBF velocity (relative change 1% and ?1.7%, p = 0.1 and 0.7). In stable patients with a continuous-flow LVAD, changes of pump speed settings within a clinically used range did not impair static cerebral autoregulation and cerebral blood flow.},
	doi = {10.33549/physiolres.934738},
	pmid = {34717062 [Indexed for MEDLINE]},
	note = {PMC8815470}
}

@ARTICLE{10.1002/ejhf.2344,
	author = {Heusser K and Wittkoepper J and Bara C and Haverich A and Diedrich A and Levine BD and Schmitto JD and Jordan J and Tank J},
	title = {Sympathetic vasoconstrictor activity before and after left ventricular assist device implantation in patients with end-stage heart failure.},
	journal = {Eur J Heart Fail},
	year = {2021},
	abstract = {AIMS: Sympathetic overactivity, which predicts poor outcome in patients with heart failure, normalizes following cardiac transplantation. We tested the hypothesis that haemodynamic improvement following left ventricular assist device (LVAD) implantation is also associated with reductions in centrally generated sympathetic activity. METHODS AND RESULTS: In eight patients with heart failure (two women, six men, age 44-66 years), we continuously recorded electrocardiogram, beat-to-beat finger blood pressure, respiration, and muscle sympathetic nerve activity (MSNA) before and after implantation of the continuous-flow LVAD devices HeartWare HVAD (n = 4) and HeartMate II (n = 2), and the non-continuous-flow device HeartMate 3 (n = 2). LVAD implantation increased cardiac output by 1.29 ± 0.88 L/min (P = 0.060) and mean arterial pressure by 16.2 ± 7.9 mmHg (P < 0.001), while reducing pulse pressure by 25.3 ± 9.8 mmHg (P < 0.001). LVAD implantation did not change MSNA burst frequency (-1.3 ± 7.5 bursts/min, P = 0.636), total activity (+0.62 ± 1.83 au, P = 0.369), or normalized activity (+0.63 ± 4.23, P = 0.685). MSNA burst incidence was decreased (-7.8 ± 9.3 bursts/100 heart beats, P = 0.049). However, cardiac ectopy altered MSNA bursting patterns that could be mistaken for sympatholysis. CONCLUSION: Implantation of current design LVAD does not consistently normalize sympathetic activity in patients with end-stage heart failure despite haemodynamic improvement.},
	doi = {10.1002/ejhf.2344},
	pmid = {34496114 [Indexed for MEDLINE]},
	note = {PMC8939843}
}

@ARTICLE{10.1007/s13239-021-00575-2,
	author = {Packy A and D'Souza GA and Farahmand M and Herbertson L and Scully CG},
	title = {Simulating Radial Pressure Waveforms with a Mock Circulatory Flow Loop to Characterize Hemodynamic Monitoring Systems.},
	journal = {Cardiovasc Eng Technol},
	year = {2022},
	abstract = {PURPOSE: Mock circulatory loops (MCLs) can reproducibly generate physiologically relevant pressures and flows for cardiovascular device testing. These systems have been extensively used to characterize the performance of therapeutic cardiac devices, but historically MCLs have had limited use for assessing patient monitoring systems. Here, we adapted an MCL to include peripheral components and evaluated its utility for qualitative and quantitative benchtop testing of hemodynamic monitoring devices. METHODS: An MCL was designed to simulate three physiological hemodynamic states: normovolemia, cardiogenic shock, and hyperdynamic circulation. The system was assessed for stability in pressure and flow values over time, repeatability, waveform morphology, and systemic-peripheral pressure relationships. RESULTS: For each condition, cardiac output was controlled to the nearest 0.2 L/min, and flow rate and mean arterial pressure remained stable and repeatable over a 60-s period (n = 5, standard deviation of ± 0.1 L/min and ± 0.84 mmHg, respectively). Transfer function analyses showed that the systemic-peripheral relationships could be adequately manipulated. The results from this MCL were comparable to those from other published MCLs and computational simulations. However, resolving current limitations of the system would further improve its utility. Three pulse contour analysis algorithms were applied to the pressure and flow data from the MCL to demonstrate the potential role of MCLs in characterizing hemodynamic monitoring systems. CONCLUSION: Overall, the development of robust analysis methods in conjunction with modified MCLs can expand device testing applications to hemodynamic monitoring systems. Properly validated MCLs can create a stable and reproducible environment for testing patient monitoring systems over their entire operating ranges prior to clinical use.},
	doi = {10.1007/s13239-021-00575-2},
	pmid = {34472042 [Indexed for MEDLINE]},
	note = {PMC8885788}
}
